<div class="page-header"><div><h2 class="page-title">Relations post / tag</h2><p class="page-meta">Associez les articles aux tags.</p></div><div class="page-actions"><a class="btn btn-primary"href="/admin/post-tags/create">Nouvelle relation</a></div></div><?php if(!empty($relations)): ?><div class="card table-card"><table class="admin-table"><thead><tr><th>Post ID</th><th>Article</th><th>Tag ID</th><th>Tag</th><th>Actions</th></tr></thead><tbody><?php foreach($relations as $relation): ?><tr><td><?=(int)$relation['post_id']?></td><td><?=htmlspecialchars($relation['post_title'])?></td><td><?=(int)$relation['tag_id']?></td><td><?=htmlspecialchars($relation['tag_name'])?></td><td><div class="table-actions"><a class="btn btn-ghost"href="/admin/post-tags/<?=(int)$relation['post_id']?>/<?=(int)$relation['tag_id']?>/edit">Modifier</a><form action="/admin/post-tags/<?=(int)$relation['post_id']?>/<?=(int)$relation['tag_id']?>/delete"method="post"onsubmit='return confirm("Supprimer cette relation ?")'><button class="btn btn-danger"type="submit">Supprimer</button></form></div></td></tr><?php endforeach; ?></tbody></table></div><?php else: ?><p class="page-meta">Aucune relation post/tag enregistree.</p><?php endif; ?>